return {
    ["line.conversation_wrath_intro.1"] = { en = "So. Fresh blood for the sand. The crowd does love a debut -- win or die.", ja = "ほう、砂場に新しい血か。観衆はデビュー戦が大好きだ――勝つか、死ぬかだ。" },
